# Backend changes (src/app/models.py)
class ChatMessage(BaseModel):
    role: Literal["user", "assistant"]
    content: str

class ChatRequest(BaseModel):
    message: str
    history: list[ChatMessage] = Field(default_factory=list)

# src/app/api.py (modified handler)
@router.post("/chat", response_model=ChatResponse)
async def chat(request: ChatRequest) -> ChatResponse:
    if not os.getenv("OPENAI_API_KEY"):
        raise HTTPException(status_code=500, detail="OpenAI API key not set")
    # Build the full conversation list for LangChain
    conversation = [
        {"role": msg.role, "content": msg.content} for msg in request.history
    ]
    conversation.append({"role": "user", "content": request.message})
    try:
        answer = await llm.ainvoke(conversation)
        return ChatResponse(answer=answer)
    except Exception as exc:
        raise HTTPException(status_code=502, detail=str(exc))

# Frontend changes (client/src/App.tsx) – abbreviated
interface ChatEntry { role: 'user' | 'assistant'; content: string; }
const [history, setHistory] = useState<ChatEntry[]>([]);
const handleSend = async () => {
  const payload = { message, history };
  const resp = await axios.post('/api/chat', payload);
  setHistory([...history, { role: 'user', content: message }, { role: 'assistant', content: resp.data.answer }]);
  setMessage('');
};
// Render history before the textarea
{history.map((e,i) => (
  <div key={i} className={e.role === 'user' ? 'text-right' : 'text-left'}>
    <span className={e.role === 'user' ? 'font-bold' : ''}>{e.content}</span>
  </div>
))}
